И теперь, когда мы поняли концепцию, можно перейти к реализации на C.
❯ Реализация на C
Сам алгоритм (без учета хеш-алгоритма) обходится примерно в 100 строк кода, а памяти требуется ровно столько, сколько нужно для хранения регистров — 16 384 байта при выбранной нами точности
.
Прежде чем говорить о самом HyperLogLog, нужно уделить внимание хеш-функции. От её качества зависит всё: если хеш-функция распределяет биты неравномерно или имеет зависимости между битами, теоретические гарантии алгоритма рушатся.
Я взял MurmurHash3 — современную некриптографическую хеш-функцию, которая известна своей скоростью и отличным распределением. В реализации представлен 64-битный вариант этой функции, адаптированный специально для HyperLogLog.
static inline uint64_t murmur3_fmix64(uint64_t k) {
 k ^= k >> 33;
 k *= 0xff51afd7ed558ccdULL;
 k ^= k >> 33;
 k *= 0xc4ceb9fe1a85ec53ULL;
 k ^= k >> 33;
 return k;
}

static inline uint64_t murmur3_64(const void* key, size_t len, uint64_t seed) {
 const uint8_t* data = (const uint8_t*)key;
 const int nblocks = len / 16;
 uint64_t h1 = seed;
 uint64_t h2 = seed;

 const uint64_t c1 = 0x87c37b91114253d5ULL;
 const uint64_t c2 = 0x4cf5ad432745937fULL;

 const uint64_t* blocks = (const uint64_t*)data;

 for (int i = 0; i < nblocks; i++) {
 uint64_t k1 = blocks[i * 2];
 uint64_t k2 = blocks[i * 2 + 1];

 k1 *= c1;
 k1 = (k1 << 31) | (k1 >> 33);
 k1 *= c2;
 h1 ^= k1;
 h1 = (h1 << 27) | (h1 >> 37);
 h1 += h2;
 h1 = h1 * 5 + 0x52dce729;

 k2 *= c2;
 k2 = (k2 << 33) | (k2 >> 31);
 k2 *= c1;
 h2 ^= k2;
 h2 = (h2 << 31) | (h2 >> 33);
 h2 += h1;
 h2 = h2 * 5 + 0x38495ab5;
 }

 const uint8_t* tail = data + nblocks * 16;
 uint64_t k1 = 0;
 uint64_t k2 = 0;

 switch (len & 15) {
 case 15:
 k2 ^= (uint64_t)tail[14] << 48;
 case 14:
 k2 ^= (uint64_t)tail[13] << 40;
 case 13:
 k2 ^= (uint64_t)tail[12] << 32;
 case 12:
 k2 ^= (uint64_t)tail[11] << 24;
 case 11:
 k2 ^= (uint64_t)tail[10] << 16;
 case 10:
 k2 ^= (uint64_t)tail[9] << 8;
 case 9:
 k2 ^= (uint64_t)tail[8];
 k2 *= c2;
 k2 = (k2 << 33) | (k2 >> 31);
 k2 *= c1;
 h2 ^= k2;
 case 8:
 k1 ^= (uint64_t)tail[7] << 56;
 case 7:
 k1 ^= (uint64_t)tail[6] << 48;
 case 6:
 k1 ^= (uint64_t)tail[5] << 40;
 case 5:
 k1 ^= (uint64_t)tail[4] << 32;
 case 4:
 k1 ^= (uint64_t)tail[3] << 24;
 case 3:
 k1 ^= (uint64_t)tail[2] << 16;
 case 2:
 k1 ^= (uint64_t)tail[1] << 8;
 case 1:
 k1 ^= (uint64_t)tail[0];
 k1 *= c1;
 k1 = (k1 << 31) | (k1 >> 33);
 k1 *= c2;
 h1 ^= k1;
 }

 h1 ^= len;
 h2 ^= len;
 h1 += h2;
 h2 += h1;

 h1 = murmur3_fmix64(h1);
 h2 = murmur3_fmix64(h2);
 h1 += h2;
 h2 += h1;

 return h1;
}
Эта функция обрабатывает входные данные блоками по 16 байт, перемешивая биты с помощью умножений и сдвигов. На выходе мы получаем 64 бита, которые ведут себя как равномерно случайные — идеальное сырьё для нашего вероятностного алгоритма.
Кстати, этот алгоритм в виде ГПСЧ я описывал в
одной из своих статей
.
Сама структура HyperLogLog удивительно проста — это массив 8-битных регистров:
#define HLL_P 14
#define HLL_M (1 << HLL_P) // 16384
#define HLL_SEED 0xadc83b19adc83b19ULL

typedef struct {
 uint8_t registers[HLL_M];
} HyperLogLog;
Почему
uint8_t
? Максимальный ранг, который мы можем получить, — это 64 минус количество битов, отданных под индекс регистра. При
максимальный ранг равен 50. Восьми битов (диапазон 0–255) более чем достаточно. Если бы мы захотели использовать
, то максимальный ранг стал бы 48 — всё равно влезает в
uint8_t
.
Инициализация сводится к обнулению всех регистров и подготовке таблицы обратных степеней двойки:
static double* inv_pow2_table = NULL;

static void hll_init_inv_pow2(void) {
 static int initialized = 0;
 if (initialized) return;
 for (int i = 0; i < 64; i++) {
 inv_pow2_table[i] = 1.0 / (double)(1ULL << i);
 }
 initialized = 1;
}

void hll_init(HyperLogLog* hll) {
 memset(hll->registers, 0, HLL_M);
 hll_init_inv_pow2();
}
Таблица
inv_pow2_table
хранит предвычисленные значения
для
от 0 до 63. Это небольшое ускорение: вместо того чтобы каждый раз вычислять степень двойки при оценке, мы просто берём готовое значение из массива.
Функция ранга — это то место, где битовые трюки встречаются с математикой (версия у меня упрощенная,
rho(w) = 1 + clz((w << p) | (1ULL << (p-1)))
):
static inline uint8_t hll_rank(uint64_t hash, uint8_t p) {
 uint64_t rest = hash << p;
 if (rest == 0) {
 return 64 - p + 1;
 }
 return __builtin_clzll(rest) + 1;
}
Разберём, что здесь происходит. На входе у нас есть 64-битный хеш. Первые
битов мы уже использовали для определения индекса корзины, поэтому они нас больше не интересуют. Мы сдвигаем хеш влево на
позиций, отбрасывая эти биты. В оставшихся
битах мы ищем позицию первого единичного бита.
Функция
__builtin_clzll
(count leading zeros) — это встроенная инструкция процессора, которая считает количество ведущих нулей в 64-битном числе. Большинство современных компиляторов (GCC, Clang) поддерживают её. Если бы мы писали код для Visual Studio, пришлось бы использовать
__lzcnt64
или реализовывать эту операцию через битовые операции, но встроенная инструкция работает за один такт и значительно ускоряет алгоритм.
Особый случай — когда после сдвига все биты обнулились. Это означает, что в оставшихся
битах не было ни одной единицы. Тогда ранг равен
(все биты нулевые, плюс единица за то, что мы «перешли» за границу).
Добавление элемента — это три простых шага: хеширование, определение индекса, обновление регистра.
void hll_add(HyperLogLog* hll, const char* element) {
 uint64_t hash = murmur3_64_string(element, HLL_SEED);
 uint32_t index = hash >> (64 - HLL_P);
 uint8_t rank = hll_rank(hash, HLL_P);
 if (rank > hll->registers[index]) {
 hll->registers[index] = rank;
 }
}
Обратите внимание на вычисление индекса:
hash >> (64 - HLL_P)
. Это эффективный способ взять старшие
битов хеша. При
мы сдвигаем 64-битное число вправо на 50 позиций, оставляя только 14 старших битов. Получается число от 0 до 16383 — идеальный индекс в массиве.
Функция
hll_rank
получает тот же самый хеш, но работает с ним иначе: она использует биты после сдвига, как мы разобрали выше.
Функция оценки — самая объёмная часть, но она просто реализует трёхуровневую коррекцию, о которой мы говорили в теоретической части:
uint64_t hll_estimate(const HyperLogLog* hll) {
 double sum = 0.0;
 int zero_registers = 0;

 for (int i = 0; i < HLL_M; i++) {
 sum += inv_pow2_table[hll->registers[i]];
 if (hll->registers[i] == 0) zero_registers++;
 }

 double raw = hll_alpha() * (double)((uint64_t)HLL_M * HLL_M) / sum;

 if (raw <= 2.5 * HLL_M) {
 if (zero_registers > 0) {
 return (uint64_t)((double)HLL_M * log((double)HLL_M / (double)zero_registers));
 }
 return (uint64_t)raw;
 }

 return (uint64_t)raw;
}
Обратите внимание на использование
inv_pow2_table[registers[i]]
— мы заранее вычислили
для всех возможных
. Это ускоряет подсчёт суммы, избавляя от вычисления степеней на лету.
Множитель
hll_alpha()
зависит от точности
и вычисляется по формуле или по таблице:
static double hll_alpha(uint8_t p, uint32_t m) {
 switch (p) {
 case 4: return 0.673;
 case 5: return 0.697;
 case 6: return 0.709;
 case 7: return 0.715;
 case 8: return 0.718;
 case 9: return 0.719;
 case 10: return 0.720;
 case 11: return 0.7205;
 default: return 0.7213 / (1.0 + 1.079 / (double)m);
 }
}
